    #[test]
    fn agent_to_message_assistant_with_tool_calls() {
        use crate::session::ContentBlock;
        let agent = AgentMessage::Assistant {
            content: vec![
                ContentBlock::Text { text: "result".to_string() },
                ContentBlock::ToolCall { tool_call: ToolCall {
                    id: "call_1".to_string(),
                    name: "my_tool".to_string(),
                    arguments: serde_json::json!({"key": "val"}),
                }},
            ],
            usage: None,
        };
        let msg = agent_message_to_message(&agent);
        match msg {
            Message::Assistant { content, reasoning, tool_calls } => {
                assert_eq!(content, "result");
                assert_eq!(reasoning, "");
                assert_eq!(tool_calls.len(), 1);
                assert_eq!(tool_calls[0].name, "my_tool");
            }
            _ => panic!("expected Assistant message"),
        }
    }

    // ---------------------------------------------------------------------------
    // accumulate_tool_call
    // ---------------------------------------------------------------------------

    #[test]
    fn accumulate_tool_call_first_delta() {
        let mut pending = Vec::new();
        let delta = ToolCallDelta {
            index: 0,
            id: Some("call_1".to_string()),
            name: Some("my_tool".to_string()),
            arguments: Some("{}".to_string()),
        };
        accumulate_tool_call(&mut pending, &delta);
        assert_eq!(pending.len(), 1);
        assert_eq!(pending[0].id, "call_1");
        assert_eq!(pending[0].name, "my_tool");
        assert_eq!(pending[0].arguments, "{}");
    }

    #[test]
    fn accumulate_tool_call_multiple_deltas() {
        let mut pending = Vec::new();

        // First delta: id + name
        accumulate_tool_call(&mut pending, &ToolCallDelta {
            index: 0,
            id: Some("call_1".to_string()),
            name: Some("my_tool".to_string()),
            arguments: None,
        });

        // Second delta: arguments fragment
        accumulate_tool_call(&mut pending, &ToolCallDelta {
            index: 0,
            id: None,
            name: None,
            arguments: Some("{\"key\":".to_string()),
        });

        // Third delta: more arguments
        accumulate_tool_call(&mut pending, &ToolCallDelta {
            index: 0,
            id: None,
            name: None,
            arguments: Some("\"val\"}".to_string()),
        });

        assert_eq!(pending[0].arguments, "{\"key\":\"val\"}");
    }

    #[test]
    fn accumulate_tool_call_gaps_in_index() {
        let mut pending = Vec::new();
        // Index 2 → should create slots 0, 1, 2
        accumulate_tool_call(&mut pending, &ToolCallDelta {
            index: 2,
            id: Some("call_3".to_string()),
            name: Some("tool_3".to_string()),
            arguments: None,
        });
        assert_eq!(pending.len(), 3);
        assert_eq!(pending[2].id, "call_3");
    }

