    // ---------------------------------------------------------------------------
    // parse_tool_call_arguments
    // ---------------------------------------------------------------------------

    #[test]
    fn parse_tool_call_arguments_valid_json() {
        let result = parse_tool_call_arguments(r#"{"path": "src/main.rs", "limit": 10}"#);
        assert!(result.is_some());
        let value = result.unwrap();
        assert_eq!(value["path"], "src/main.rs");
        assert_eq!(value["limit"], 10);
    }

    #[test]
    fn parse_tool_call_arguments_empty_string() {
        let result = parse_tool_call_arguments("");
        assert!(result.is_some());
        assert_eq!(result.unwrap(), serde_json::json!({}));
    }

    #[test]
    fn parse_tool_call_arguments_whitespace_only() {
        let result = parse_tool_call_arguments("   \n\t  ");
        assert!(result.is_some());
        assert_eq!(result.unwrap(), serde_json::json!({}));
    }

    #[test]
    fn parse_tool_call_arguments_missing_closing_brace() {
        // Incomplete JSON — missing closing `}`
        let result = parse_tool_call_arguments(r#"{"path": "src/main.rs""#);
        assert!(result.is_some(), "should repair missing closing brace");
        let value = result.unwrap();
        assert_eq!(value["path"], "src/main.rs");
    }

    #[test]
    fn parse_tool_call_arguments_trailing_comma() {
        // Trailing comma — invalid in strict JSON
        let result = parse_tool_call_arguments(r#"{"path": "src/main.rs", "limit": 10,"#);
        assert!(result.is_some(), "should handle trailing comma");
        let value = result.unwrap();
        assert_eq!(value["path"], "src/main.rs");
    }

    #[test]
    fn parse_tool_call_arguments_unclosed_string() {
        // Unclosed string value
        let result = parse_tool_call_arguments(r#"{"key": "value"#);
        assert!(result.is_some(), "should repair unclosed string");
        let value = result.unwrap();
        assert_eq!(value["key"], "value");
    }

    #[test]
    fn parse_tool_call_arguments_nested_incomplete() {
        // Nested object with missing closing braces
        let result = parse_tool_call_arguments(r#"{"outer": {"inner": "val""#);
        assert!(result.is_some(), "should repair nested incomplete JSON");
        let value = result.unwrap();
        assert_eq!(value["outer"]["inner"], "val");
    }

    #[test]
    fn parse_tool_call_arguments_empty_object() {
        let result = parse_tool_call_arguments("{}");
        assert!(result.is_some());
        assert_eq!(result.unwrap(), serde_json::json!({}));
    }

    #[test]
    fn parse_tool_call_arguments_just_opening_brace() {
        let result = parse_tool_call_arguments("{");
        assert!(result.is_some(), "should repair lone opening brace");
        assert_eq!(result.unwrap(), serde_json::json!({}));
    }

    #[test]
    fn parse_tool_call_arguments_key_without_value() {
        // Key with no value after colon
        let result = parse_tool_call_arguments(r#"{"key":"#);
        assert!(result.is_some(), "should handle key without value");
        let value = result.unwrap();
        assert!(value["key"].is_null());
    }
